{
  "debrief": [
    {
      "explanation": "When you traced one frozen clip stop by stop, you were following how data actually travels — broken into labeled pieces sent separately, not as one stream. The relay dropping pieces out of order was packet switching failing at one node.",
      "name": "Packet Switching"
    },
    {
      "explanation": "Each room the signal passed through was a hop. Comparing what entered and left each handoff — like you did in Step 2 — is exactly how networks isolate which hop is the culprit, not just which cable looks bad.",
      "name": "Hop-by-Hop Routing"
    },
    {
      "explanation": "That tiny test burst you sent out and back in Step 3? That's measuring round-trip time. When one return lagged far behind the others, RTT gave the weak link a name instead of a guess.",
      "name": "Round-Trip Time (RTT)"
    },
    {
      "explanation": "When rehearsal doubled traffic and you rerouted everything to the spare path, congestion hit immediately. Too many packets competing for one route causes exactly the freezes you were trying to fix — more senders never solve a jammed pipe.",
      "name": "Network Congestion"
    },
    {
      "explanation": "Showing the route map, the delayed return, and the relay mismatch in Step 5 is what network engineers call path tracing. Isolating the bad relay — not rebooting everything around it — is what actually cleared the stream.",
      "name": "Path Tracing and Isolation"
    }
  ],
  "outcomes": [
    {
      "minStrongChoices": 5,
      "narrative": "You traced every packet, named every bottleneck, and swapped the bad relay before the show opened. The sponsor saw the stream recover live, and the control room remembered who fixed it.",
      "title": "Clear Signal All Night"
    },
    {
      "minStrongChoices": 3,
      "narrative": "You found the core problem and patched most of it, but a few guesses cost time and trust. The show aired clean, though the crew knows the fix wasn't airtight.",
      "title": "Steady Enough to Broadcast"
    },
    {
      "minStrongChoices": 1,
      "narrative": "Some feeds steadied, others kept stumbling. You kept the stream alive through a mix of luck and workarounds, but the freezes never fully stopped and the room never fully relaxed.",
      "title": "Survived, Barely"
    },
    {
      "minStrongChoices": 0,
      "narrative": "Every shortcut made the problem harder to find. The freezes won this round — but now you know exactly why each choice backfired, and that's worth more than a smooth night you didn't understand.",
      "title": "The Stream Won Tonight"
    }
  ]
}

